"use client"

import * as React from "react"

import { DiscussionPostCardDrawer } from "./discussion-post-card-drawer"
import { DiscussionPostCardPreview } from "./discussion-post-card-preview"
import type {
  DiscussionPostCardProps,
  DrawerDirection,
  VoteDirection,
} from "./types"

function useResolvedDirection(direction: DrawerDirection) {
  const [isDesktop, setIsDesktop] = React.useState(false)

  React.useEffect(() => {
    const mediaQuery = window.matchMedia("(min-width: 768px)")
    const sync = () => setIsDesktop(mediaQuery.matches)
    sync()
    mediaQuery.addEventListener("change", sync)
    return () => mediaQuery.removeEventListener("change", sync)
  }, [])

  return direction === "auto" ? (isDesktop ? "right" : "bottom") : direction
}

export function DiscussionPostCard({
  profileImage,
  name,
  createdAt,
  content,
  currentUpvoteCount,
  currentDownvoteCount,
  hideDownvoteCount = false,
  onUpvoteClick,
  onDownvoteClick,
  initialBookmarked = false,
  replies = [],
  replyText,
  onReplyTextChange,
  onReplySubmit,
  replyPlaceholder,
  drawerDirection = "auto",
  drawerBottomInsetClassName,
  drawerBodyClassName,
  drawerPinFooter = true,
  drawerFooterClassName,
}: DiscussionPostCardProps) {
  const [open, setOpen] = React.useState(false)
  const [isBookmarked, setIsBookmarked] = React.useState(initialBookmarked)
  const [voteDirection, setVoteDirection] = React.useState<VoteDirection>(null)
  const [voteCounts, setVoteCounts] = React.useState({
    upvotes: currentUpvoteCount,
    downvotes: currentDownvoteCount,
  })
  const resolvedDirection = useResolvedDirection(drawerDirection)

  React.useEffect(() => {
    setVoteCounts({
      upvotes: currentUpvoteCount,
      downvotes: currentDownvoteCount,
    })
  }, [currentUpvoteCount, currentDownvoteCount])

  const handleUpvoteClick = () => {
    setVoteCounts((current) => {
      if (voteDirection === "up") {
        setVoteDirection(null)
        return {
          upvotes: Math.max(current.upvotes - 1, 0),
          downvotes: current.downvotes,
        }
      }

      if (voteDirection === "down") {
        setVoteDirection("up")
        return {
          upvotes: current.upvotes + 1,
          downvotes: Math.max(current.downvotes - 1, 0),
        }
      }

      setVoteDirection("up")
      return {
        upvotes: current.upvotes + 1,
        downvotes: current.downvotes,
      }
    })
    onUpvoteClick()
  }

  const handleDownvoteClick = () => {
    setVoteCounts((current) => {
      if (voteDirection === "down") {
        setVoteDirection(null)
        return {
          upvotes: current.upvotes,
          downvotes: Math.max(current.downvotes - 1, 0),
        }
      }

      if (voteDirection === "up") {
        setVoteDirection("down")
        return {
          upvotes: Math.max(current.upvotes - 1, 0),
          downvotes: current.downvotes + 1,
        }
      }

      setVoteDirection("down")
      return {
        upvotes: current.upvotes,
        downvotes: current.downvotes + 1,
      }
    })
    onDownvoteClick()
  }

  return (
    <>
      <DiscussionPostCardPreview
        profileImage={profileImage}
        name={name}
        createdAt={createdAt}
        content={content}
        currentUpvoteCount={voteCounts.upvotes}
        currentDownvoteCount={voteCounts.downvotes}
        hideDownvoteCount={hideDownvoteCount}
        voteDirection={voteDirection}
        isBookmarked={isBookmarked}
        onBookmarkClick={() => setIsBookmarked((current) => !current)}
        onUpvoteClick={handleUpvoteClick}
        onDownvoteClick={handleDownvoteClick}
        onReplyClick={() => setOpen(true)}
        replyCount={replies.length}
      />

      <DiscussionPostCardDrawer
        profileImage={profileImage}
        name={name}
        createdAt={createdAt}
        content={content}
        currentUpvoteCount={voteCounts.upvotes}
        currentDownvoteCount={voteCounts.downvotes}
        hideDownvoteCount={hideDownvoteCount}
        voteDirection={voteDirection}
        onUpvoteClick={handleUpvoteClick}
        onDownvoteClick={handleDownvoteClick}
        replies={replies}
        replyText={replyText}
        onReplyTextChange={onReplyTextChange}
        onReplySubmit={onReplySubmit}
        replyPlaceholder={replyPlaceholder}
        isBookmarked={isBookmarked}
        onBookmarkClick={() => setIsBookmarked((current) => !current)}
        open={open}
        onOpenChange={setOpen}
        resolvedDirection={resolvedDirection}
        drawerBottomInsetClassName={drawerBottomInsetClassName}
        drawerBodyClassName={drawerBodyClassName}
        drawerPinFooter={drawerPinFooter}
        drawerFooterClassName={drawerFooterClassName}
      />
    </>
  )
}

import {
  ArrowBigDown,
  ArrowBigUp,
  Bookmark,
  MessageCircle,
} from "lucide-react";
import type { ReactNode } from "react";

import { RichTextContent } from "./rich-text-content";
import type { DiscussionPostCardProps, VoteDirection } from "./types";

type DiscussionPostCardPreviewProps = Pick<
  DiscussionPostCardProps,
  "profileImage" | "name" | "createdAt" | "content" | "hideDownvoteCount"
> & {
  currentUpvoteCount: number;
  currentDownvoteCount: number;
  isBookmarked?: boolean;
  onBookmarkClick?: () => void;
  onUpvoteClick: () => void;
  onDownvoteClick: () => void;
  onReplyClick?: () => void;
  replyCount: number;
  showReplyAction?: boolean;
  showBookmarkAction?: boolean;
  showDivider?: boolean;
  voteDirection?: VoteDirection;
};

type CountActionButtonProps = {
  icon: ReactNode;
  value: number;
  onClick: () => void;
  srLabel: string;
  hideValue?: boolean;
  isActive?: boolean;
};

function CountActionButton({
  icon,
  value,
  onClick,
  srLabel,
  hideValue = false,
  isActive = false,
}: CountActionButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`cursor-pointer inline-flex items-center gap-[4px] rounded-[16px] px-[8px] py-[4px] text-[#3B3435] transition-colors hover:text-[#111928] ${
        isActive
          ? "bg-[#E5E7EB] text-[#111928]"
          : "bg-[#F3F4F6] hover:bg-[#E5E7EB]"
      }`}
    >
      {icon}
      {!hideValue ? (
        <span className="text-[12px] font-[400] leading-[16px] text-[#111928]">
          {value}
        </span>
      ) : null}
      <span className="sr-only">{srLabel}</span>
    </button>
  );
}

export function DiscussionPostCardPreview({
  profileImage,
  name,
  createdAt,
  content,
  currentUpvoteCount,
  currentDownvoteCount,
  hideDownvoteCount = false,
  isBookmarked = false,
  onBookmarkClick,
  onUpvoteClick,
  onDownvoteClick,
  onReplyClick,
  replyCount,
  showReplyAction = true,
  showBookmarkAction = true,
  showDivider = true,
  voteDirection = null,
}: DiscussionPostCardPreviewProps) {
  return (
    <article className="font-poppins w-full w-[100%] rounded-[12px] border border-[#E5E7EB] bg-white p-[12px]">
      <header className="flex items-start justify-between gap-3">
        <div className="flex items-center gap-[8px]">
          <img
            src={profileImage}
            alt={name}
            className="size-[36px] rounded-full"
          />
          <div className="min-w-0">
            <h3 className="truncate text-[14px] font-[500] leading-[20px] text-[#111928]">
              {name}
            </h3>
            <p className="text-[12px] leading-[16px] font-[400] text-[#4B5563]">
              {createdAt}
            </p>
          </div>
        </div>

        {showBookmarkAction ? (
          <button
            type="button"
            onClick={onBookmarkClick ?? (() => {})}
            className="cursor-pointer"
          >
            <Bookmark
              color="#544D4F"
              size={24}
              className={isBookmarked ? "fill-current" : ""}
            />
            <span className="sr-only">Bookmark discussion</span>
          </button>
        ) : null}
      </header>

      <RichTextContent
        html={content}
        className="mt-[12px] text-[14px] font-[400] leading-[20px] text-[#4B5563]"
      />

      {showDivider ? <div className="h-[1px] my-[16px] w-full bg-[#E5E7EB]" /> : null}
      <div className={showDivider ? "" : "mt-[16px]"}>
        <div className="flex flex-wrap items-center gap-[16px]">
          <CountActionButton
            icon={
              <ArrowBigUp
                size={16}
                color="#374151"
                className={voteDirection === "up" ? "fill-current" : ""}
              />
            }
            value={currentUpvoteCount}
            onClick={onUpvoteClick}
            srLabel="Upvote discussion"
            isActive={voteDirection === "up"}
          />
          <CountActionButton
            icon={
              <ArrowBigDown
                size={16}
                color="#374151"
                className={voteDirection === "down" ? "fill-current" : ""}
              />
            }
            value={currentDownvoteCount}
            onClick={onDownvoteClick}
            srLabel="Downvote discussion"
            hideValue={hideDownvoteCount}
            isActive={voteDirection === "down"}
          />
          {showReplyAction ? (
            <CountActionButton
              icon={<MessageCircle size={16} color="#374151" />}
              value={replyCount}
              onClick={onReplyClick ?? (() => {})}
              srLabel="Open replies"
            />
          ) : null}
        </div>
      </div>
    </article>
  );
}

"use client";

import * as React from "react";
import * as Dialog from "@radix-ui/react-dialog";
import { X } from "lucide-react";

import { DiscussionPostCardPreview } from "./discussion-post-card-preview";
import { DiscussionPostCardComposer } from "./discussion-post-card-composer";
import type {
  DiscussionPostCardProps,
  DrawerDirection,
  VoteDirection,
} from "./types";

import { cn } from "@/lib/utils";

type DiscussionPostCardDrawerProps = Pick<
  DiscussionPostCardProps,
  | "profileImage"
  | "name"
  | "createdAt"
  | "content"
  | "currentUpvoteCount"
  | "currentDownvoteCount"
  | "voteDirection"
  | "hideDownvoteCount"
  | "onUpvoteClick"
  | "onDownvoteClick"
  | "replies"
  | "replyText"
  | "onReplyTextChange"
  | "onReplySubmit"
  | "replyPlaceholder"
  | "drawerBottomInsetClassName"
  | "drawerBodyClassName"
  | "drawerPinFooter"
  | "drawerFooterClassName"
> & {
  isBookmarked: boolean;
  onBookmarkClick: () => void;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  resolvedDirection: Exclude<DrawerDirection, "auto">;
};

export function DiscussionPostCardDrawer({
  profileImage,
  name,
  createdAt,
  content,
  currentUpvoteCount,
  currentDownvoteCount,
  voteDirection = null,
  hideDownvoteCount = false,
  onUpvoteClick,
  onDownvoteClick,
  replies = [],
  replyText,
  onReplyTextChange,
  onReplySubmit,
  replyPlaceholder,
  isBookmarked,
  onBookmarkClick,
  open,
  onOpenChange,
  resolvedDirection,
  drawerBottomInsetClassName,
  drawerBodyClassName,
  drawerPinFooter = true,
  drawerFooterClassName,
}: DiscussionPostCardDrawerProps) {
  const [replyVotes, setReplyVotes] = React.useState<
    Record<string, { upvotes: number; downvotes: number; direction: VoteDirection }>
  >({});

  React.useEffect(() => {
    setReplyVotes(
      replies.reduce<
        Record<string, { upvotes: number; downvotes: number; direction: VoteDirection }>
      >(
        (accumulator, reply) => {
          accumulator[reply.id] = {
            upvotes: reply.currentUpvoteCount ?? 0,
            downvotes: reply.currentDownvoteCount ?? 0,
            direction: reply.voteDirection ?? null,
          };
          return accumulator;
        },
        {},
      ),
    );
  }, [replies]);

  const composerFooter = (
    <div
      className={cn(
        "bg-white",
        drawerPinFooter && "shrink-0 border-t p-4",
        drawerPinFooter &&
          resolvedDirection === "bottom" &&
          "shadow-[0_-4px_16px_rgba(0,0,0,0.06)]",
        !drawerPinFooter && "mt-4 border-t border-[#E5E7EB] pt-4",
        drawerFooterClassName,
      )}
    >
      <DiscussionPostCardComposer
        profileImage={profileImage}
        replyText={replyText}
        onReplyTextChange={onReplyTextChange}
        onReplySubmit={onReplySubmit}
        placeholder={replyPlaceholder}
      />
    </div>
  );

  return (
    <Dialog.Root open={open} onOpenChange={onOpenChange}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-50 bg-black/50 transition-opacity duration-300 ease-out data-[state=closed]:opacity-0 data-[state=open]:opacity-100" />
        <Dialog.Content
          className={cn(
            "fixed z-50 border bg-white font-poppins shadow-xl outline-none",
            resolvedDirection === "right"
              ? "right-0 top-0 flex h-svh w-full max-w-[460px] flex-col border-l transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-x-full data-[state=open]:translate-x-0"
              : "bottom-0 left-0 flex max-h-[88svh] w-full flex-col rounded-t-2xl border-t transition-transform duration-300 ease-out will-change-transform data-[state=closed]:translate-y-full data-[state=open]:translate-y-0",
            drawerBottomInsetClassName,
          )}
        >
          <div className="flex items-start justify-between border-b p-4">
            <Dialog.Title className="text-lg font-semibold text-[#111928]">
              Discussion Thread
            </Dialog.Title>
            <Dialog.Close className="inline-flex size-8 items-center justify-center rounded-md border text-[#6B7280] hover:bg-[#F9FAFB] hover:text-[#111928]">
              <X size={16} />
              <span className="sr-only">Close</span>
            </Dialog.Close>
          </div>

          <div
            className={cn(
              "min-h-0 flex-1 overflow-y-auto p-4",
              drawerBodyClassName,
            )}
          >
            <DiscussionPostCardPreview
              profileImage={profileImage}
              name={name}
              createdAt={createdAt}
              content={content}
              currentUpvoteCount={currentUpvoteCount}
              currentDownvoteCount={currentDownvoteCount}
              voteDirection={voteDirection}
              hideDownvoteCount={hideDownvoteCount}
              isBookmarked={isBookmarked}
              onBookmarkClick={onBookmarkClick}
              onUpvoteClick={onUpvoteClick}
              onDownvoteClick={onDownvoteClick}
              replyCount={replies.length}
              showReplyAction={false}
            />

            <div className="mt-4">
              <p className="text-[14px] font-[600] leading-[20px] text-[#111928]">
                Responses
              </p>
              {replies.length ? (
                <div className="mt-3 space-y-3">
                  {replies.map((reply) => (
                    <DiscussionPostCardPreview
                      key={reply.id}
                      profileImage={
                        reply.profileImage ||
                        "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=120&q=80"
                      }
                      name={reply.author}
                      createdAt={reply.createdAt}
                      content={reply.content}
                      currentUpvoteCount={replyVotes[reply.id]?.upvotes ?? 0}
                      currentDownvoteCount={
                        replyVotes[reply.id]?.downvotes ?? 0
                      }
                      voteDirection={replyVotes[reply.id]?.direction ?? null}
                      hideDownvoteCount={hideDownvoteCount}
                      onUpvoteClick={() => {
                        setReplyVotes((current) => {
                          const currentState = current[reply.id] ?? {
                            upvotes: 0,
                            downvotes: 0,
                            direction: null,
                          };

                          if (currentState.direction === "up") {
                            return {
                              ...current,
                              [reply.id]: {
                                ...currentState,
                                upvotes: Math.max(currentState.upvotes - 1, 0),
                                direction: null,
                              },
                            };
                          }

                          if (currentState.direction === "down") {
                            return {
                              ...current,
                              [reply.id]: {
                                upvotes: currentState.upvotes + 1,
                                downvotes: Math.max(currentState.downvotes - 1, 0),
                                direction: "up",
                              },
                            };
                          }

                          return {
                            ...current,
                            [reply.id]: {
                              ...currentState,
                              upvotes: currentState.upvotes + 1,
                              direction: "up",
                            },
                          };
                        });
                      }}
                      onDownvoteClick={() => {
                        setReplyVotes((current) => {
                          const currentState = current[reply.id] ?? {
                            upvotes: 0,
                            downvotes: 0,
                            direction: null,
                          };

                          if (currentState.direction === "down") {
                            return {
                              ...current,
                              [reply.id]: {
                                ...currentState,
                                downvotes: Math.max(currentState.downvotes - 1, 0),
                                direction: null,
                              },
                            };
                          }

                          if (currentState.direction === "up") {
                            return {
                              ...current,
                              [reply.id]: {
                                upvotes: Math.max(currentState.upvotes - 1, 0),
                                downvotes: currentState.downvotes + 1,
                                direction: "down",
                              },
                            };
                          }

                          return {
                            ...current,
                            [reply.id]: {
                              ...currentState,
                              downvotes: currentState.downvotes + 1,
                              direction: "down",
                            },
                          };
                        });
                      }}
                      replyCount={0}
                      showReplyAction={false}
                      showBookmarkAction={false}
                      showDivider={false}
                    />
                  ))}
                </div>
              ) : (
                <div className="mt-3 rounded-[10px] border border-dashed border-[#D1D5DB] bg-[#F9FAFB] p-4 text-[13px] text-[#6B7280]">
                  No replies yet. Start the discussion.
                </div>
              )}
            </div>

            {!drawerPinFooter ? composerFooter : null}
          </div>

          {drawerPinFooter ? composerFooter : null}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

"use client";

import { SendHorizontal } from "lucide-react";

import { RichTextEditor } from "./rich-text-editor";

type DiscussionPostCardComposerProps = {
  profileImage?: string;
  replyText: string;
  onReplyTextChange: (value: string) => void;
  onReplySubmit?: () => void;
  placeholder?: string;
  showOuterRoundedBorder?: boolean;
};

export function DiscussionPostCardComposer({
  profileImage,
  replyText,
  onReplyTextChange,
  onReplySubmit,
  placeholder = "Write your reply...",
  showOuterRoundedBorder = true,
}: DiscussionPostCardComposerProps) {
  const hasReplyText =
    replyText
      .replace(/<[^>]*>/g, "")
      .replace(/&nbsp;/g, " ")
      .trim().length > 0;
  const isMultilineReply =
    /<br\s*\/?>/i.test(replyText) ||
    /<\/p>\s*<p>/i.test(replyText) ||
    replyText.includes("\n");

  return (
    <div
      className={`flex items-start gap-3 bg-[#F9FAFB] p-[12px] shadow-[0_1px_3px_0_rgba(0,0,0,0.11)] ${
        showOuterRoundedBorder ? "rounded-[12px]" : ""
      }`}
    >
      <img
        src={
          profileImage ||
          "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=120&q=80"
        }
        alt="Your profile"
        className="mt-1 size-9 shrink-0 self-start rounded-full border border-[#E5E7EB] object-cover"
      />
      <div className="relative min-w-0 flex-1">
        <label className="sr-only" htmlFor="discussion-reply-input">
          Write a reply
        </label>
        <RichTextEditor
          value={replyText}
          onChange={onReplyTextChange}
          placeholder={placeholder}
          showToolbar={false}
          contentClassName={`!min-h-[40px] !max-h-[140px] !overflow-y-auto !bg-white !py-[10px] !pl-[12px] !pr-14 [&_p]:!my-0 ${
            isMultilineReply ? "!rounded-[12px]" : "!rounded-[104px]"
          }`}
        />
        <button
          type="button"
          onClick={onReplySubmit}
          disabled={!hasReplyText}
          className="absolute bottom-[6px] right-[8px] inline-flex size-8 cursor-pointer items-center justify-center rounded-full bg-[#EF8833] text-white transition-colors hover:bg-[#DC7A2D] disabled:cursor-not-allowed disabled:bg-[#E5E7EB] disabled:text-[#9CA3AF]"
        >
          <SendHorizontal size={14} />
          <span className="sr-only">Send reply</span>
        </button>
      </div>
    </div>
  );
}

"use client"

import * as React from "react"
import StarterKit from "@tiptap/starter-kit"
import { EditorContent, useEditor, useEditorState } from "@tiptap/react"
import {
  Bold,
  Italic,
  List,
  ListOrdered,
} from "lucide-react"

type RichTextEditorProps = {
  value: string
  onChange: (value: string) => void
  placeholder?: string
  className?: string
  contentClassName?: string
  showToolbar?: boolean
}

export function RichTextEditor({
  value,
  onChange,
  placeholder = "Write here...",
  className = "",
  contentClassName = "",
  showToolbar = true,
}: RichTextEditorProps) {
  const contentBorderClass = showToolbar
    ? "rounded-b-lg border border-t-0 border-[#E5E7EB]"
    : "rounded-lg border border-[#E5E7EB]"

  const [isMounted, setIsMounted] = React.useState(false)

  React.useEffect(() => {
    setIsMounted(true)
  }, [])

  const editor = useEditor({
    extensions: [StarterKit],
    content: value || "<p></p>",
    editorProps: {
      attributes: {
        class:
          `min-h-24 ${contentBorderClass} px-3 py-2 text-[14px] leading-[22px] text-[#111928] outline-none [&_h1]:my-2 [&_h1]:text-[28px] [&_h1]:font-[700] [&_h1]:leading-[36px] [&_h2]:my-2 [&_h2]:text-[22px] [&_h2]:font-[600] [&_h2]:leading-[30px] [&_h3]:my-2 [&_h3]:text-[18px] [&_h3]:font-[600] [&_h3]:leading-[26px] [&_p]:my-2 [&_ul]:my-2 [&_ul]:list-disc [&_ul]:pl-5 [&_ol]:my-2 [&_ol]:list-decimal [&_ol]:pl-5 [&_li]:my-1 [&_blockquote]:border-l-2 [&_blockquote]:border-[#E5E7EB] [&_blockquote]:pl-3 ${contentClassName}`,
      },
    },
    onUpdate: ({ editor: tiptapEditor }) => {
      onChange(tiptapEditor.getHTML())
    },
    immediatelyRender: false,
  })

  React.useEffect(() => {
    if (!editor) return
    const current = editor.getHTML()
    if (current !== value) {
      editor.commands.setContent(value || "<p></p>", { emitUpdate: false })
    }
  }, [editor, value])

  const editorState = useEditorState({
    editor,
    selector: ({ editor }) => ({
      isBold: editor?.isActive("bold") ?? false,
      isItalic: editor?.isActive("italic") ?? false,
      isBulletList: editor?.isActive("bulletList") ?? false,
      isOrderedList: editor?.isActive("orderedList") ?? false,
      isEmpty: editor?.isEmpty ?? true,
    }),
  })

  const toolbarButtonClass = (isActive: boolean) =>
    `inline-flex h-8 w-8 items-center justify-center rounded-md border border-[#E5E7EB] transition-colors ${
      isActive
        ? "bg-[#FDE8D7] text-[#B45309]"
        : "text-[#4B5563] hover:bg-[#F9FAFB]"
    }`

  if (!isMounted || !editor) {
    return (
      <textarea
        value={value}
        onChange={(event) => onChange(event.target.value)}
        placeholder={placeholder}
        className={`min-h-24 w-full resize-y rounded-lg border border-[#E5E7EB] px-3 py-2 text-[14px] leading-[22px] text-[#111928] outline-none placeholder:text-[#9CA3AF] ${className}`}
      />
    )
  }

  return (
    <div className={`discussion-rich-editor relative ${className}`}>
      {showToolbar ? (
        <div className="flex flex-wrap items-center gap-2 rounded-t-lg border border-[#E5E7EB] p-2">
        <button
          type="button"
          onMouseDown={(event) => event.preventDefault()}
          onClick={() => editor?.chain().focus().toggleBold().run()}
          className={toolbarButtonClass(editorState?.isBold ?? false)}
        >
          <Bold size={14} />
        </button>
        <button
          type="button"
          onMouseDown={(event) => event.preventDefault()}
          onClick={() => editor?.chain().focus().toggleItalic().run()}
          className={toolbarButtonClass(editorState?.isItalic ?? false)}
        >
          <Italic size={14} />
        </button>
        <button
          type="button"
          onMouseDown={(event) => event.preventDefault()}
          onClick={() => editor?.chain().focus().toggleBulletList().run()}
          className={toolbarButtonClass(editorState?.isBulletList ?? false)}
        >
          <List size={14} />
        </button>
        <button
          type="button"
          onMouseDown={(event) => event.preventDefault()}
          onClick={() => editor?.chain().focus().toggleOrderedList().run()}
          className={toolbarButtonClass(editorState?.isOrderedList ?? false)}
        >
          <ListOrdered size={14} />
        </button>
        </div>
      ) : null}
      <EditorContent editor={editor} />
      {editorState?.isEmpty ? (
        <p
          className={`pointer-events-none absolute left-3 right-3 text-[14px] leading-[22px] text-[#9CA3AF] ${
            showToolbar ? "top-[52px]" : "top-[10px]"
          }`}
        >
          {placeholder}
        </p>
      ) : null}
    </div>
  )
}

"use client"

import * as React from "react"
import createDOMPurify from "dompurify"

type RichTextContentProps = {
  html: string
  className?: string
}

export function RichTextContent({ html, className = "" }: RichTextContentProps) {
  const sanitizedHtml = React.useMemo(() => {
    if (typeof window === "undefined") return html
    const purifier = createDOMPurify(window)
    return purifier.sanitize(html)
  }, [html])

  return (
    <div
      className={`break-words [overflow-wrap:anywhere] [&_h1]:my-2 [&_h1]:text-[28px] [&_h1]:font-[700] [&_h1]:leading-[36px] [&_h1]:break-words [&_h2]:my-2 [&_h2]:text-[22px] [&_h2]:font-[600] [&_h2]:leading-[30px] [&_h2]:break-words [&_h3]:my-2 [&_h3]:text-[18px] [&_h3]:font-[600] [&_h3]:leading-[26px] [&_h3]:break-words [&_p]:my-2 [&_p]:break-words [&_ul]:my-2 [&_ul]:list-disc [&_ul]:pl-5 [&_ol]:my-2 [&_ol]:list-decimal [&_ol]:pl-5 [&_li]:my-1 [&_li]:break-words [&_blockquote]:border-l-2 [&_blockquote]:border-[#E5E7EB] [&_blockquote]:pl-3 [&_blockquote]:break-words ${className}`}
      dangerouslySetInnerHTML={{ __html: sanitizedHtml }}
    />
  )
}
